export default function ProductItem({ product, onEdit, onDelete }) {
  const handleDeleteClick = () => {
    console.log("Кнопка УДАЛИТЬ нажата → ID:", product.id);
    
    if (window.confirm(`Удалить позицию "${product.title}"?`)) {
      console.log("Пользователь подтвердил удаление");
      onDelete(product.id);
    } else {
      console.log("Удаление отменено");
    }
  };

  return (
    <div className="menu-card">
      <h3>{product.title}</h3>
      <p><strong>Категория:</strong> {product.category}</p>
      <p>{product.description}</p>
      <p><strong>Цена:</strong> {product.price} ₽</p>
      <p><strong>Остаток:</strong> {product.stock} шт.</p>

      <div style={{ marginTop: '16px' }}>
        <button 
          className="btn" 
          onClick={() => onEdit(product)}
        >
          Редактировать
        </button>
        
        <button 
          className="btn delete" 
          onClick={handleDeleteClick}
          style={{ marginLeft: '12px', background: '#e74c3c' }}
        >
          Удалить
        </button>
      </div>
    </div>
  );
}
